rule.example:

public class Foo {
    public void Bar(bool flag) {
        // flag signals two responsibilities
    }
}


public class Foo {
    public void Bar(bool flag) {
        if (flag) {
            // one branch
        } else {
            // another branch
        }
    }
}


public class Foo {
    public void Bar(string input) {
        string result;
        if ((result = Process(input)) != null) { // assignment in condition
            Use(result);
        }
    }
}


var d = new Dictionary<string, int> {
    ["foo"] = 1,
    ["foo"] = 2,  // duplicate key, first declaration is dead
};


public class Foo {
    public void Bar() {
        Baz.DoSomething(); // static access to another class
    }
}
